import React from 'react';
import { Link } from 'react-router-dom';

export default function Logo({ size = 'md', light = false }) {
  const fontSize = size === 'lg' ? '22px' : size === 'sm' ? '14px' : '18px';
  return (
    <Link to="/" style={{ display: 'inline-flex', alignItems: 'center', gap: '2px', textDecoration: 'none' }}>
      <span style={{
        fontFamily: "'Irish Gr",
        fontSize,
        fontWeight: 400,
        color: light ? '#fff' : 'var(--primary)',
        letterSpacing: '-0.3px'
      }}>My</span>
      <span style={{
        fontFamily: "'Cormorant Garamond', serif",
        fontSize: `calc(${fontSize} + 2px)`,
        fontStyle: 'italic',
        fontWeight: 600,
        color: light ? '#fff' : 'var(--primary)',
        letterSpacing: '-0.3px'
      }}>Guestly</span>
      <span style={{
        fontFamily: "'DM Sans', sans-serif",
        fontSize,
        fontWeight: 700,
        color: 'var(--secondary)',
        marginLeft: '3px'
      }}>Ai</span>
    </Link>
  );
}
